{
  "name": "Meeting Intelligence Extractor",
  "description": "Automated extraction of structured entities (Summary, Decisions, Tech Stack) from meeting audio or transcripts using Gemini 2.5 Flash.",
  "requestFramePermissions": [
    "microphone"
  ]
}

export interface ActionItem {
  who: string;
  what: string;
  dueDate?: string;
}

export interface Decision {
  decision: string;
  context: string;
}

export interface MeetingAnalysis {
  summary: string;
  topics: string[];
  decisions: Decision[];
  actionItems: ActionItem[];
  techDetails: string[];
  projects: string[];
  blockers: string[];
}

export type ProcessingStatus = 'idle' | 'uploading' | 'processing' | 'completed' | 'error';

export interface ProcessingError {
  message: string;
  code?: string;
}

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { MeetingAnalysis } from "../types";

// Initialize Gemini client
// Note: In a real backend (FastAPI as per TZ), this would happen server-side.
// Here we simulate the "Microservice" logic in the browser.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// The Schema matching the TZ requirements
const analysisSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    summary: {
      type: Type.STRING,
      description: "A brief summary of the meeting (3-5 sentences).",
    },
    topics: {
      type: Type.ARRAY,
      items: { type: Type.STRING },
      description: "List of discussed topics.",
    },
    decisions: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          decision: { type: Type.STRING },
          context: { type: Type.STRING, description: "Context or reasoning behind the decision." },
        },
        required: ["decision", "context"],
      },
      description: "Decisions made during the meeting.",
    },
    actionItems: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          who: { type: Type.STRING, description: "Person responsible (or 'Unknown')." },
          what: { type: Type.STRING, description: "The task description." },
        },
        required: ["who", "what"],
      },
      description: "Action items extracted from the conversation.",
    },
    techDetails: {
      type: Type.ARRAY,
      items: { type: Type.STRING },
      description: "Technical stack details, API names, architectural decisions, configs.",
    },
    projects: {
      type: Type.ARRAY,
      items: { type: Type.STRING },
      description: "Mentioned codebases, internal services, or project names.",
    },
    blockers: {
      type: Type.ARRAY,
      items: { type: Type.STRING },
      description: "Problems, risks, and obstacles mentioned.",
    },
  },
  required: ["summary", "topics", "decisions", "actionItems", "techDetails", "projects", "blockers"],
};

// Helper to convert File to Base64
const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const result = reader.result as string;
      // Remove data url prefix (e.g. "data:audio/mp3;base64,")
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = (error) => reject(error);
  });
};

export const analyzeMeeting = async (file: File): Promise<MeetingAnalysis> => {
  try {
    const base64Data = await fileToBase64(file);
    const mimeType = file.type;

    // We use gemini-2.5-flash-latest as it is robust for multimodal (Audio -> Text -> Logic)
    // The prompt includes the System Instruction as per TZ.
    const model = "gemini-flash-latest"; 

    const systemPrompt = `
    You are a Systems Analyst. Your task is to process the meeting audio/transcript and extract structured intelligence.

    1. **Tech Details**: If a database, API method, library, or specific architecture is mentioned, extract it here.
    2. **Action Items**: If someone says "I will do this" or "Let's assign this to X", create an Action Item.
    3. **Decisions**: Explicitly agreed upon points.
    4. **Blockers**: Any raised concerns, risks, or impediments.

    Ensure the output is strictly valid JSON matching the schema.
    `;

    const response = await ai.models.generateContent({
      model: model,
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: mimeType,
              data: base64Data,
            },
          },
          {
            text: "Analyze this meeting audio.",
          },
        ],
      },
      config: {
        systemInstruction: systemPrompt,
        temperature: 0, // As per TZ: minimize hallucinations
        responseMimeType: "application/json",
        responseSchema: analysisSchema,
      },
    });

    const text = response.text;
    if (!text) {
      throw new Error("No response generated from model.");
    }

    return JSON.parse(text) as MeetingAnalysis;

  } catch (error) {
    console.error("Analysis failed:", error);
    throw error;
  }
};

import React from 'react';

const Hero: React.FC = () => {
  return (
    <div className="text-center py-10 px-4">
      <div className="inline-flex items-center justify-center p-3 bg-brand-50 rounded-full mb-4">
