// Helper to convert File to Base64
const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const result = reader.result as string;
      // Remove data url prefix (e.g. "data:audio/mp3;base64,")
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = (error) => reject(error);
  });
};

export const analyzeMeeting = async (file: File, language: string = "English", projectContext?: string, feedback?: string): Promise<MeetingAnalysis> => {
  try {
    const base64Data = await fileToBase64(file);
    const mimeType = file.type;

    // We use gemini-flash-latest (mapping to gemini-2.5-flash-latest per instructions)
    const model = "gemini-flash-latest"; 

    let systemPrompt = `
    You are a Systems Analyst. Your task is to process the meeting audio/transcript and extract structured intelligence.

    1. **Tech Details**: If a database, API method, library, or specific architecture is mentioned, extract it here.
    2. **Action Items**: If someone says "I will do this" or "Let's assign this to X", create an Action Item.
    3. **Decisions**: Explicitly agreed upon points.
    4. **Blockers**: Any raised concerns, risks, or impediments.

    IMPORTANT: All text content in the JSON response (summary, topics, descriptions, decision context, etc.) MUST be written in ${language}.

    Ensure the output is strictly valid JSON matching the schema.
    `;

    if (projectContext) {
      systemPrompt += `\n\nPROJECT CONTEXT & TERMINOLOGY:\nThe user has provided specific context for this project. Use these definitions to better understand acronyms, project names, and technical specifics:\n"""\n${projectContext}\n"""\n`;
    }

    let userPrompt = `Analyze this meeting audio and output the results in ${language}.`;

    if (feedback) {
      userPrompt += `\n\nIMPORTANT CORRECTION REQUEST: The user has identified errors in a previous analysis of this file. 
      Please re-analyze the audio with the following corrections in mind: 
      "${feedback}"

      Fix any misunderstood terms, entities, or contexts based on this feedback and regenerate the full report.`;
    }

    const response = await ai.models.generateContent({
      model: model,
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: mimeType,
              data: base64Data,
            },
          },
          {
            text: userPrompt,
          },
        ],
      },
      config: {
        systemInstruction: systemPrompt,
        temperature: 0, // As per TZ: minimize hallucinations
        responseMimeType: "application/json",
        responseSchema: analysisSchema,
      },
    });

    const text = response.text;
    if (!text) {
      throw new Error("No response generated from model.");
    }

    return JSON.parse(text) as MeetingAnalysis;

  } catch (error) {
    console.error("Analysis failed:", error);
    throw error;
  }
};

import React, { useState, useRef } from 'react';
import { Project } from '../types';
import { importProjectsFromFile } from '../services/projectService';

interface ProjectManagerProps {
  projects: Project[];
  onAdd: (project: Project) => void;
  onUpdate: (project: Project) => void;
  onDelete: (id: string) => void;
  onImport: (projects: Project[]) => void;
  onExport: () => void;
  isOpen: boolean;
  onClose: () => void;
}

const ProjectManager: React.FC<ProjectManagerProps> = ({ 
  projects, onAdd, onUpdate, onDelete, onImport, onExport, isOpen, onClose 
}) => {
  const [editingId, setEditingId] = useState<string | null>(null);
  const [formData, setFormData] = useState({ name: '', context: '' });
  const fileInputRef = useRef<HTMLInputElement>(null);

  if (!isOpen) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name.trim()) return;

    if (editingId) {
      const existing = projects.find(p => p.id === editingId);
      if (existing) {
        onUpdate({ ...existing, name: formData.name, context: formData.context });
      }
      setEditingId(null);
    } else {
      onAdd({
        id: crypto.randomUUID(),
        name: formData.name,
        context: formData.context
      });
    }
    setFormData({ name: '', context: '' });
  };

  const handleEdit = (project: Project) => {
    setEditingId(project.id);
    setFormData({ name: project.name, context: project.context });
  };

  const handleCancelEdit = () => {
    setEditingId(null);
    setFormData({ name: '', context: '' });
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      try {
        const imported = await importProjectsFromFile(e.target.files[0]);
        onImport(imported);
        alert(`Successfully imported ${imported.length} projects.`);
      } catch (err) {
        alert("Failed to import projects. Check file format.");
        console.error(err);
      }
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  return (
    <div className="bg-white border border-slate-200 rounded-xl shadow-sm overflow-hidden mb-8 animate-fade-in">
      <div className="bg-slate-50 px-6 py-4 border-b border-slate-200 flex justify-between items-center">
        <h3 className="font-semibold text-slate-800 flex items-center">
          <svg className="w-5 h-5 mr-2 text-brand-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" />
          </svg>
          Project Context Manager
        </h3>
        <div className="flex gap-2">
           <button 
             onClick={() => fileInputRef.current?.click()}
             className="text-xs px-3 py-1.5 bg-white border border-slate-300 text-slate-600 rounded hover:bg-slate-50 font-medium"
           >
             Import JSON
           </button>
           <button 
             onClick={onExport}
             className="text-xs px-3 py-1.5 bg-white border border-slate-300 text-slate-600 rounded hover:bg-slate-50 font-medium"
           >
             Export JSON
           </button>
           <button onClick={onClose} className="text-slate-400 hover:text-slate-600">
             <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
             </svg>
           </button>
        </div>
        <input type="file" ref={fileInputRef} onChange={handleFileChange} accept=".json" className="hidden" />
      </div>

      <div className="p-6 grid grid-cols-1 lg:grid-cols-3 gap-8">

        {/* Project List */}
        <div className="lg:col-span-1 space-y-4 max-h-96 overflow-y-auto custom-scrollbar pr-2">
           {projects.length === 0 ? (
               <p className="text-sm text-slate-400 italic text-center py-4">No projects defined.</p>
           ) : (
               projects.map(p => (
                   <div key={p.id} className={`p-3 rounded-lg border ${editingId === p.id ? 'border-brand-500 bg-brand-50' : 'border-slate-200 bg-white hover:border-brand-300'} transition-all`}>
                       <div className="flex justify-between items-start mb-1">
