      const existing = projects.find(p => p.id === editingId);
      if (existing) {
        onUpdate({ 
          ...existing, 
          name: formData.name, 
          context: formData.context,
          team: formData.team 
        });
      }
      setEditingId(null);
    } else {
      onAdd({
        id: crypto.randomUUID(),
        name: formData.name,
        context: formData.context,
        team: formData.team
      });
    }
    setFormData({ name: '', context: '', team: '' });
