    if (feedback.trim()) {
      onReanalyze(feedback);
    }
  };

  const handleAskClick = async () => {
    if (!question.trim()) return;
    setIsAsking(true);
    setAnswer(null);
    try {
      const result = await onAskQuestion(question);
      setAnswer(result);
    } catch (e) {
      setAnswer("Sorry, I encountered an error while processing your question.");
    } finally {
      setIsAsking(false);
    }
