import express, { Request, Response } from 'express';
import multer from 'multer';
import cors from 'cors';
import { v4 as uuidv4 } from 'uuid';
import { GoogleGenAI, Type, Schema } from "@google/genai";

// Configuration
const PORT = process.env.PORT || 3000;
const API_KEY = process.env.API_KEY;

if (!API_KEY) {
  console.error("Error: API_KEY environment variable is missing.");
  process.exit(1);
}

// Initialize Gemini
const ai = new GoogleGenAI({ apiKey: API_KEY });

// In-memory storage for tasks
// In a real production app, use Redis or a Database
interface Task {
  id: string;
  status: 'processing' | 'completed' | 'failed';
  result?: any;
  error?: string;
  createdAt: number;
}

const tasks = new Map<string, Task>();

// Setup Express
const app = express();
const upload = multer({ storage: multer.memoryStorage() });

app.use(cors());
app.use(express.json());

// Schema definition (Matching the frontend types)
const analysisSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    transcript: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          speaker: { type: Type.STRING },
          timestamp: { type: Type.STRING },
          text: { type: Type.STRING },
        },
        required: ["speaker", "timestamp", "text"],
      },
    },
    summary: { type: Type.STRING },
    topics: { type: Type.ARRAY, items: { type: Type.STRING } },
    decisions: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          decision: { type: Type.STRING },
          context: { type: Type.STRING },
        },
        required: ["decision", "context"],
      },
    },
    actionItems: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          who: { type: Type.STRING },
          what: { type: Type.STRING },
        },
        required: ["who", "what"],
      },
    },
    techDetails: { type: Type.ARRAY, items: { type: Type.STRING } },
    projects: { type: Type.ARRAY, items: { type: Type.STRING } },
    blockers: { type: Type.ARRAY, items: { type: Type.STRING } },
  },
  required: ["transcript", "summary", "topics", "decisions", "actionItems", "techDetails", "projects", "blockers"],
};

// --- Endpoints ---

/**
 * POST /v1/process-meeting
 * Accepts multipart/form-data with 'file' field.
 * Optional body fields: 'context' (project context), 'team' (team members).
 */
app.post('/v1/process-meeting', upload.single('file'), async (req: Request, res: Response) => {
  try {
    if (!req.file) {
      res.status(400).json({ error: "No file provided." });
      return;
    }

    const taskId = uuidv4();
    const fileBuffer = req.file.buffer;
    const mimeType = req.file.mimetype;

    // Optional context from body
    const projectContext = req.body.context;
    const teamContext = req.body.team;
    const language = req.body.language || "English";

    // Create task
    tasks.set(taskId, {
      id: taskId,
      status: 'processing',
      createdAt: Date.now()
    });

    // Respond immediately (202 Accepted)
    res.status(202).json({ 
      task_id: taskId, 
      status: "accepted",
      message: "File uploaded and processing started." 
    });

    // Start Background Processing
    processMeetingInBackground(taskId, fileBuffer, mimeType, language, projectContext, teamContext);

  } catch (error: any) {
    console.error("Upload error:", error);
    res.status(500).json({ error: error.message });
  }
});

/**
 * GET /v1/results/:taskId
