// Helper to convert File to Base64
const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const result = reader.result as string;
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = (error) => reject(error);
  });
};

// Helper: Parse Plain Text Transcript "[MM:SS] Speaker: Text"
function parseTranscriptText(text: string) {
  const segments: { speaker: string; timestamp: string; text: string }[] = [];
  const lines = text.split('\n');
  let currentSegment: { speaker: string; timestamp: string; text: string } | null = null;
  const lineRegex = /^\[(\d{1,2}:\d{2}(?::\d{2})?)\]\s*([^:]+):\s*(.+)$/;

  for (const line of lines) {
    const cleanLine = line.trim();
    if (!cleanLine) continue;

    const match = cleanLine.match(lineRegex);
    if (match) {
      if (currentSegment) segments.push(currentSegment);
      currentSegment = {
        timestamp: match[1],
        speaker: match[2].trim(),
        text: match[3].trim()
      };
    } else {
      if (currentSegment) currentSegment.text += " " + cleanLine;
    }
  }
  if (currentSegment) segments.push(currentSegment);
  return segments;
}

